UPDATE public.articulos SET metadata = metadata || '{"unidades": ["avanzada", "clan", "compania", "manada", "tropa"], "areas": ["corporalidad", "creatividad", "sociabilidad"], "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Un vaso de leche para Santa."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convive constantemente en la naturaleza y participa en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Un vaso de leche para Santa."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Un vaso de leche para Santa."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Un vaso de leche para Santa."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso rápido y coordinando sus movimientos con sus compañeros durante la dinámica de Un vaso de leche para Santa."}, {"id": "5d2d48ed-c461-4a8e-9048-cceecd3de2e2", "area": "Corporalidad", "texto": "Me gusta jugar con otros niños y niñas y respeto las reglas de los juegos.", "unidad": "Manada", "como_se_cumple": "Corriendo a paso rápido y coordinando sus movimientos con sus compañeros durante la dinámica de Un vaso de leche para Santa."}, {"id": "58b4936a-816e-4d17-8d0a-c92d0606009d", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Un vaso de leche para Santa."}, {"id": "6768d60a-187e-4bbf-97b9-cdc25a316030", "area": "Corporalidad", "texto": "Ayudo a preparar los juegos, excursiones y campamentos de mi patrulla y mi Tropa.", "unidad": "Tropa", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Un vaso de leche para Santa."}, {"id": "843fda9c-6c4a-4516-b30c-23c92ef755a8", "area": "Creatividad", "texto": "Puedo resolver la mayoría de los problemas técnicos domésticos simples.", "unidad": "Avanzada", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en Un vaso de leche para Santa."}, {"id": "29eee8b1-a414-4df9-90e1-520a384fb9aa", "area": "Creatividad", "texto": "Une los conocimientos teórico y práctico mediante la aplicación constante de sus habilidades técnicas y manuales.", "unidad": "Clan", "como_se_cumple": "Combinando conocimientos prácticos e inventiva técnica para resolver los retos de pionerismo y diseño en Un vaso de leche para Santa."}, {"id": "103661fc-3396-4eac-9182-58b7e54d5115", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Compañía", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Un vaso de leche para Santa."}, {"id": "0f60be94-6de3-4c34-a6ff-5b5018f0b156", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Un vaso de leche para Santa."}, {"id": "8985ff05-ee84-4fba-af46-146c5374df89", "area": "Creatividad", "texto": "Participo en los talleres de manualidades que se hacen en la Manada.", "unidad": "Manada", "como_se_cumple": "Manipulando de forma segura y creativa los materiales de la actividad para modelar o construir en Un vaso de leche para Santa."}, {"id": "d4232b99-5655-49c6-9d24-099cfe9c8180", "area": "Creatividad", "texto": "Practico continuamente mis habilidades manuales.", "unidad": "Manada", "como_se_cumple": "Manipulando de forma segura y creativa los materiales de la actividad para modelar o construir en Un vaso de leche para Santa."}, {"id": "11320fb6-98de-4725-825d-db858e3bffa2", "area": "Creatividad", "texto": "Perfecciono mis habilidades manuales.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Un vaso de leche para Santa."}, {"id": "fd3d3e14-e92b-4ab5-8298-9018c6e70b20", "area": "Creatividad", "texto": "Coopero en la mantención y renovación del local y materiales de mi patrulla.", "unidad": "Tropa", "como_se_cumple": "Aplicando ingenio práctico y destrezas manuales para optimizar los recursos construidos en Un vaso de leche para Santa."}, {"id": "f1496221-0da5-4775-b3ba-29e65603cfee", "area": "Sociabilidad", "texto": "Acepto las normas de los diferentes ambientes en que actúo, sin renunciar a mi derecho de tratar de cambiarlas cuando no me parecen correctas.", "unidad": "Avanzada", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Un vaso de leche para Santa."}, {"id": "b5954f1c-4d0d-4bdb-97d8-821583beb77e", "area": "Sociabilidad", "texto": "Cumple las normas que la sociedad se ha dado, evaluándolas con responsabilidad y sin renunciar a cambiarlas.", "unidad": "Clan", "como_se_cumple": "Velando por la seguridad física y el cumplimiento estricto del reglamento de competencia en Un vaso de leche para Santa."}, {"id": "007e85ea-2b06-48c2-8ac1-873d59643aae", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Un vaso de leche para Santa."}, {"id": "de2f5693-de4b-48f1-b870-3c62be99aea8", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Compañía", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Un vaso de leche para Santa."}, {"id": "b69188bf-2391-43c1-a885-abd1b13912be", "area": "Sociabilidad", "texto": "Acepto las reglas que se ponen en mi casa, en la escuela y en la Manada.", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Un vaso de leche para Santa."}, {"id": "2394dd5b-87b9-4f3d-9cdd-a42649139782", "area": "Sociabilidad", "texto": "Comprendo y respeto las normas que se han puesto en mi casa y en la escuela, aunque no siempre esté de acuerdo con ellas", "unidad": "Manada", "como_se_cumple": "Respetando rigurosamente las reglas del juego de relevos y las instrucciones de seguridad en Un vaso de leche para Santa."}, {"id": "857f21bc-db3c-4e5e-bcd5-d3d331276fad", "area": "Sociabilidad", "texto": "Conozco y respeto las principales normas de convivencia.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Un vaso de leche para Santa."}, {"id": "bbc48d53-f4aa-4de7-84d4-95614df76034", "area": "Sociabilidad", "texto": "Respeto las normas de convivencia de los distintos ambientes en que actúo, aunque no siempre esté de acuerdo con ellas.", "unidad": "Tropa", "como_se_cumple": "Acatando las normas de fair play y cooperando en la mantención del orden colectivo durante Un vaso de leche para Santa."}]}'::jsonb WHERE id = '025298f3-9d09-45d9-9867-6de31f8d4bf9';
