UPDATE public.articulos SET metadata = metadata || '{"unidades": ["avanzada", "clan", "compania", "manada", "tropa"], "areas": ["corporalidad", "creatividad", "sociabilidad"], "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Promueve el ingenio práctico, la agilidad mental y la resolución de problemas técnicos o enigmas. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "objetivos_educativos": [{"id": "7200435f-b020-46fc-b323-8249048b1d18", "area": "Corporalidad", "texto": "Participo en la organización de juegos y actividades recreativas para los demás.", "unidad": "Avanzada", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Relevos del vaso."}, {"id": "106e27af-ec7a-45fa-9295-fcef88fbef3d", "area": "Corporalidad", "texto": "Convive constantemente en la naturaleza y participa en actividades deportivas y recreativas.", "unidad": "Clan", "como_se_cumple": "Desplegando su máximo rendimiento aeróbico, agilidad y coordinación táctica en la carrera de Relevos del vaso."}, {"id": "d5b111f1-5f6f-4716-8a02-e1826d653c59", "area": "Corporalidad", "texto": "Participo en los juegos, excursiones y campamentos que organiza mi patrulla.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Relevos del vaso."}, {"id": "b12da732-d736-480c-82b8-95b312316390", "area": "Corporalidad", "texto": "Me esfuerzo por mejorar mi rendimiento en el deporte que practico y sé ganar y perder.", "unidad": "Compañía", "como_se_cumple": "Corriendo velozmente y dosificando su energía y esfuerzo aeróbico para superar las fases físicas de Relevos del vaso."}, {"id": "4bf1e3dd-7f21-4c24-962d-9d6d64e32f25", "area": "Corporalidad", "texto": "Me gusta hacer actividades al aire libre.", "unidad": "Manada", "como_se_cumple": "Corriendo a