UPDATE public.articulos SET metadata = metadata || '{"unidades": ["compania", "manada", "tropa"], "areas": ["caracter", "corporalidad", "sociabilidad"], "justificacion_areas": "Fomenta la coordinación física y la resistencia cardiovascular mediante desafíos corporales dinámicos. Ayuda a consolidar los valores scouts de honestidad, lealtad y fair play en la competencia. Incentiva el cumplimiento de reglas, el trabajo cooperativo y el respeto de la seguridad grupal.", "objetivos_educativos": [{"id": "075c93b1-81d2-4370-8e47-f0a4d086b20e", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de botellas con agua."}, {"id": "7a9e143e-c837-473b-a014-e41ef5fc2ec2", "area": "Carácter", "texto": "Entiendo que es importante actuar de acuerdo a lo que pienso.", "unidad": "Compañía", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de botellas con agua."}, {"id": "baa365a9-087c-4c25-b0ad-57893df5ff74", "area": "Carácter", "texto": "Sé lo que significa decir la verdad.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de botellas con agua, aceptando con alegría la victoria o la derrota."}, {"id": "506b7596-cac4-48e0-88c7-942d575172db", "area": "Carácter", "texto": "Digo la verdad, aunque a veces no me gusten las consecuencias.", "unidad": "Manada", "como_se_cumple": "Jugando de manera transparente y honesta en Carrera de botellas con agua, aceptando con alegría la victoria o la derrota."}, {"id": "38f4863e-12a6-4a4b-9767-8cdf55020734", "area": "Carácter", "texto": "Sé lo que significa ser leal.", "unidad": "Tropa", "como_se_cumple": "Demostrando lealtad con sus compañeros y respeto por la palabra empeñada en el transcurso de Carrera de botellas con agua."}, {"id": "5311be36-87be-40c4-ab4a-e6ce6e662183", "area": "Carác